import { useMemo } from 'react';
import type { EChartsOption, CustomSeriesRenderItemAPI, CustomSeriesRenderItemParams } from 'echarts';

import { cn } from '../utils/cn';
import { LOAD_STATE_COLORS } from './common/chart-colors';
import { HChart } from './HChart';
import type { GanttSegment } from './types';

type GanttChartProps = {
  data: GanttSegment[];
  height?: number;
  showTooltip?: boolean;
  showXAxis?: boolean;
  className?: string;
};

function formatTime(ms: number): string {
  const d = new Date(ms);
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

/**
 * Specialized ECharts wrapper for Gantt / timeline charts showing load states.
 *
 * Each segment is rendered as a coloured rectangle based on the device load
 * state. Defaults to 24 px height with no axes for a compact Gantt bar.
 */
function GanttChart({
  data,
  height = 24,
  showTooltip = false,
  showXAxis = false,
  className,
}: GanttChartProps) {
  const option = useMemo<EChartsOption>(() => {
    if (data.length === 0) {
      return { xAxis: { show: false }, yAxis: { show: false }, series: [] };
    }

    const minTime = Math.min(...data.map((s) => s.start));
    const maxTime = Math.max(...data.map((s) => s.end));

    const seriesData = data.map((segment, index) => ({
      value: [index, segment.start, segment.end, segment.state],
      itemStyle: {
        color: LOAD_STATE_COLORS[segment.state] ?? LOAD_STATE_COLORS.nodata,
      },
      name: segment.label,
    }));

    const renderItem = (
      params: CustomSeriesRenderItemParams,
      api: CustomSeriesRenderItemAPI,
    ) => {
      const startCoord = api.coord([api.value(1), 0]);
      const endCoord = api.coord([api.value(2), 0]);

      const coordSys = params.coordSys as unknown as { x: number; y: number; height: number } | undefined;
      const rectX = startCoord[0];
      const rectWidth = endCoord[0] - startCoord[0];
      const rectY = coordSys?.y ?? 0;
      const rectHeight = coordSys?.height ?? height;

      return {
        type: 'rect' as const,
        shape: {
          x: rectX,
          y: rectY,
          width: Math.max(rectWidth, 1),
          height: rectHeight,
        },
        style: api.style(),
      };
    };

    return {
      animation: false,
      grid: {
        top: 0,
        bottom: showXAxis ? 20 : 0,
        left: 0,
        right: 0,
        containLabel: false,
      },
      xAxis: {
        type: 'value',
        min: minTime,
        max: maxTime,
        show: showXAxis,
        axisLabel: {
          formatter: (val: number) => formatTime(val),
        },
      },
      yAxis: {
        show: false,
      },
      tooltip: showTooltip
        ? {
            trigger: 'item',
            formatter: (params: any) => {
              const value = params.value;
              const state = value[3] as string;
              const label = params.name || state;
              const start = formatTime(value[1]);
              const end = formatTime(value[2]);
              return `<strong>${label}</strong><br/>${start} – ${end}`;
            },
          }
        : { show: false },
      series: [
        {
          type: 'custom',
          renderItem,
          encode: {
            x: [1, 2],
          },
          data: seriesData,
        },
      ],
    };
  }, [data, height, showTooltip, showXAxis]);

  return (
    <div data-slot="gantt-chart" className={cn('w-full', className)}>
      <HChart option={option} height={height} />
    </div>
  );
}

export { GanttChart };
export type { GanttChartProps };
